// Home PV Control users.
// Blueprint-compatible multi-inverter version with main/debug dashboard configuration.
// HBC remains untouched except optional selection of input_select.house_battery_strategy.

function states() {
    return global.get('homeassistant.homeAssistant.states') || {};
}

function getState(entity, fallback = undefined) {
    const s = states();
    if (!entity || !s[entity]) return fallback;
    return s[entity].state;
}

function numEntity(entity, fallback = 0) {
    const v = parseFloat(getState(entity, fallback));
    return Number.isFinite(v) ? v : fallback;
}

function strEntity(entity, fallback = '') {
    const v = getState(entity, fallback);
    return v === undefined || v === null ? fallback : String(v);
}

// Configuration helper wrappers. Kept separate from numEntity()/strEntity() for readability
// and future helper-specific validation.
function helperNum(entity, fallback = 0) {
    return numEntity(entity, fallback);
}

function helperStr(entity, fallback = '') {
    return strEntity(entity, fallback);
}

function clamp(v, min, max) {
    return Math.min(Math.max(v, min), max);
}

function serviceMsg(domain, service, data, target) {
    return { payload: { action: `${domain}.${service}`, data, target } };
}

function validEntity(entity) {
    return typeof entity === 'string' && entity.includes('.');
}

function entityExists(entity) {
    if (!validEntity(entity)) return false;
    const s = states();
    if (!s[entity]) return false;
    const st = String(s[entity].state || '').trim().toLowerCase();
    return !['unknown', 'unavailable', 'none', ''].includes(st);
}

function stateIsNumeric(entity) {
    const st = states()[entity] && states()[entity].state;
    if (st === undefined || st === null) return false;
    const text = String(st).trim().toLowerCase();
    if (['unknown', 'unavailable', 'none', ''].includes(text)) return false;
    return Number.isFinite(parseFloat(text));
}

function pickedEntity(pickerEntity, textEntity, fallback = '') {
    const picked = helperStr(pickerEntity, '').trim();
    if (validEntity(picked) && picked !== 'select_entity_first') return picked;

    // Fallback to legacy/manual input_text entity fields when the dropdown is not set yet.
    const typed = helperStr(textEntity, '').trim();
    if (validEntity(typed) && typed !== 'select_entity_first') return typed;

    return validEntity(fallback) ? fallback : '';
}


function insightTime() {
    const d = new Date();
    const hh = String(d.getHours()).padStart(2, '0');
    const mm = String(d.getMinutes()).padStart(2, '0');
    const ss = String(d.getSeconds()).padStart(2, '0');
    return `${hh}:${mm}:${ss}`;
}

function insight(source, node, message) {
    const body = `${module} | ${node} | ${message}`;
    const line = `${insightTime()} | ${body}`;
    const key = body.trim();
    // Deduplicate inside one EMS run as well as against stored history.
    if (!newInsights.some(item => item.key === key)) {
        newInsights.push({ line, key });
    }
}

function insightBody(line) {
    const parts = String(line || '').split('|').map(p => p.trim());
    return parts.length >= 4 ? parts.slice(1).join(' | ').trim() : String(line || '').trim();
}

const now = Date.now();
const enabled = strEntity('input_boolean.pv_ems_enabled', 'on') === 'on';
const notify = strEntity('input_boolean.pv_ems_notifications', 'on') === 'on';
const hbcControlRequested = strEntity('input_boolean.pv_ems_control_hbc_strategy', 'off') === 'on';

// Configurable entity IDs
const gridEntity = pickedEntity('input_select.pv_ems_grid_power_sensor_picker', 'input_text.pv_ems_grid_power_sensor', '');
const marketEntity = pickedEntity('input_select.pv_ems_market_price_sensor_picker', 'input_text.pv_ems_market_price_sensor', '');
const allInEntity = pickedEntity('input_select.pv_ems_all_in_price_sensor_picker', 'input_text.pv_ems_all_in_price_sensor', '');
const pvPowerEntity = pickedEntity('input_select.pv_ems_pv_power_sensor_picker', 'input_text.pv_ems_pv_power_sensor', '');
const hbcStrategyEntity = pickedEntity('input_select.pv_ems_battery_strategy_entity_picker', 'input_text.pv_ems_battery_strategy_entity', 'input_select.house_battery_strategy');
const hasHbc = entityExists(hbcStrategyEntity);
const controlHbc = hbcControlRequested && hasHbc;

// Live values
const market = numEntity(marketEntity, 999);
const allIn = numEntity(allInEntity, 999);
const grid = numEntity(gridEntity, 0);        // negative export, positive import
const pvPower = numEntity(pvPowerEntity, 0);


// Settings
const limitingPrice = helperNum('input_number.pv_ems_pv_limiting_price', 0.00);
const chargePrice = helperNum('input_number.pv_ems_battery_charge_price', 0.10);
const expensivePrice = helperNum('input_number.pv_ems_battery_expensive_price', 0.25);
const hysteresis = helperNum('input_number.pv_ems_battery_price_hysteresis', 0.02);

const exportStart = helperNum('input_number.pv_ems_export_start_threshold', -200);
const exportTarget = helperNum('input_number.pv_ems_export_stop_threshold', -25);
const importRecalc = helperNum('input_number.pv_ems_import_restore_threshold', 200);
const minPvPower = helperNum('input_number.pv_ems_pv_min_power_for_control', 100);
const nightRestorePower = helperNum('input_number.pv_ems_pv_night_restore_power', 10);
const cooldownSeconds = helperNum('input_number.pv_ems_cooldown_seconds', 60);
const deadband = helperNum('input_number.pv_ems_pv_adjust_deadband', 25);

const balancedStrategy = strEntity('input_select.pv_ems_balanced_strategy', 'Dynamic 2');
const expensiveStrategy = strEntity('input_select.pv_ems_expensive_strategy', 'Sell');
const currentStrategy = strEntity(hbcStrategyEntity, 'unknown');

// Inverter configuration from blueprint-compatible helpers.
// User selects inverter count (1-10). Only the first N slots are used.
const inverterCount = Math.round(clamp(helperNum('input_number.pv_ems_inverter_count', 1), 1, 10));
const configuredInverters = [];
for (let i = 1; i <= inverterCount; i++) {
    configuredInverters.push({
        name: `PV${i}`,
        limit_entity: pickedEntity(`input_select.pv_ems_pv${i}_limit_number_picker`, `input_text.pv_ems_pv${i}_limit_number`, ''),
        full_power: helperNum(`input_number.pv_ems_pv${i}_full_limit`, 0),
        minimum_power: helperNum(`input_number.pv_ems_pv${i}_low_limit`, 0)
    });
}

let inverters = configuredInverters
    .filter(inv => validEntity(inv.limit_entity) && inv.full_power > 0 && inv.minimum_power >= 0)
    .map(inv => ({ ...inv, current: numEntity(inv.limit_entity, inv.full_power) }));

const outputs = Array(9).fill(null);
// outputs:
// 0 generic inverter limit calls, 1 status, 2 reason, 3 last action,
// 4 targets json, 5 notification, 6 HBC strategy, 7 rolling insights, 8 force HBC toggle off

let status = 'Idle';
let reason = 'No action';
let pvAction = 'none';
let batteryOption = null;
let notification = null;
let notificationCalls = [];
let targetTotal = 0;
let targets = [];
let newInsights = [];
let hbcStatusText = hasHbc ? `HBC detected: ${hbcStrategyEntity}` : 'HBC not detected';

if (hbcControlRequested && !hasHbc) {
    hbcStatusText = 'HBC not detected - HBC control forced off';
    outputs[8] = serviceMsg('input_boolean', 'turn_off', {}, { entity_id: 'input_boolean.pv_ems_control_hbc_strategy' });
    insight('Home PV Control', 'HBC detection', 'HBC strategy entity not found; HBC control forced off');
}

const marketValid = stateIsNumeric(marketEntity);
const allInValid = stateIsNumeric(allInEntity);
const totalFull = inverters.reduce((s, inv) => s + inv.full_power, 0);
const totalMin = inverters.reduce((s, inv) => s + inv.minimum_power, 0);

// Strict PV cooldown gate.
// Every PV write starts a flow-owned cooldown window. During that window no PV action is allowed.
// On the first evaluation after the window ends, only the "cooldown finished" insight is allowed;
// the next PV limit/restore/recalculation can only happen on the following evaluation.
// This guarantees the insight order around every PV adjustment:
// PV limit/Restore/Recalculation -> Cooldown active -> Cooldown finished -> next possible PV adjustment.
const cooldownMs = Math.max(0, cooldownSeconds * 1000);
const cooldownUntilMs = Number(flow.get('homePvControlCooldownUntilMs') || 0);
const previousCooldownActive = flow.get('homePvControlCooldownActive') === true;
const cooldownActiveComputed = cooldownUntilMs > now;
const cooldownJustFinished = previousCooldownActive && !cooldownActiveComputed;
const canChangePv = !cooldownActiveComputed && !cooldownJustFinished;
let cooldownActiveNow = cooldownActiveComputed;

const wantsMinimumPv = allInValid && allIn <= 0;
const atMinimumPv = inverters.length > 0 && inverters.every(inv => inv.current <= (inv.minimum_power + deadband));
const wasNegativeMinimumMode = flow.get('homePvControlNegativeMinimumActive') === true;

// Required setup validation. Empty helpers stay empty; no personal/default entities are injected.
let missing = [];
if (!validEntity(gridEntity)) missing.push('Grid power sensor');
if (!validEntity(marketEntity)) missing.push('Market price sensor');
if (!validEntity(allInEntity)) missing.push('All-in price sensor');
if (!validEntity(pvPowerEntity)) missing.push('PV power sensor');
if (hbcControlRequested && !hasHbc) missing.push('HBC strategy entity');
for (const inv of configuredInverters) {
    if (!validEntity(inv.limit_entity)) missing.push(`${inv.name} limit entity`);
    if (!(inv.full_power > 0)) missing.push(`${inv.name} max/full limit`);
    if (inv.full_power > 0 && inv.minimum_power >= inv.full_power) missing.push(`${inv.name} minimum must be lower than full limit`);
}

if (!enabled) {
    status = 'Disabled';
    reason = 'Home PV Control is disabled';
    insight('Home PV Control', 'Master control', 'Home PV Control disabled; no PV or HBC actions sent');
} else if (missing.length > 0) {
    status = 'Configuration error';
    reason = `Missing: ${missing.join(', ')}`;
    insight('Home PV Control', 'Configuration', reason);
} else if (inverters.length === 0 || totalFull <= 0) {
    status = 'Configuration error';
    reason = 'No valid PV inverter limit entities configured';
    insight('Home PV Control', 'Configuration', 'No valid PV inverter limit entities configured');
} else {
    // Target total PV limit: PV power + grid power - target grid power.
    // Example: PV 2500, grid -600, target -25 => 2500 - 600 + 25 = 1925.
    const rawTarget = pvPower + grid - exportTarget;
    targetTotal = Math.round(clamp(rawTarget, totalMin, totalFull));

    targets = inverters.map(inv => {
        const ratio = totalFull > 0 ? inv.full_power / totalFull : 0;
        const target = Math.round(clamp(targetTotal * ratio, inv.minimum_power, inv.full_power));
        return {
            name: inv.name,
            entity: inv.limit_entity,
            current: inv.current,
            target,
            full_power: inv.full_power,
            minimum_power: inv.minimum_power,
            changed: Math.abs(inv.current - target) > deadband
        };
    });

    const anyBelowFull = inverters.some(inv => inv.current < (inv.full_power - deadband));
    const targetChanged = targets.some(t => t.changed);
    const targetIsFull = targets.length > 0 && targets.every(t => t.target >= (t.full_power - deadband));
    const targetIsMinimum = targets.length > 0 && targets.every(t => t.target <= (t.minimum_power + deadband));

    const shouldForceMinimum =
    canChangePv &&
    !atMinimumPv &&
    (
        wantsMinimumPv ||
        (
            targetIsMinimum &&
            marketValid &&
            market <= limitingPrice &&
            pvPower > minPvPower &&
            grid < exportStart
        )
    );

    const shouldRestore =
        anyBelowFull &&
        !wantsMinimumPv &&
        canChangePv &&
        (
            (wasNegativeMinimumMode && atMinimumPv) ||
            !marketValid ||
            market > limitingPrice ||
            pvPower < nightRestorePower ||
            targetIsFull
        );

    const shouldAdjust =
        !shouldForceMinimum &&
        !shouldRestore &&
        !targetIsFull &&
        !targetIsMinimum &&
        !wantsMinimumPv &&
        marketValid &&
        targetChanged &&
        market <= limitingPrice &&
        pvPower > minPvPower &&
        canChangePv &&
        (
            grid < exportStart ||
            grid > importRecalc
        );

    if (shouldForceMinimum) {
        pvAction = 'minimum';
        status = wantsMinimumPv ? 'PV minimum - negative price' : 'PV minimum limit';
        reason = wantsMinimumPv
            ? 'All-in price is zero or negative; force PV to minimum'
            : 'Calculated target is minimum power';
    } else if (shouldRestore) {
        pvAction = 'restore';
        status = 'PV restored';
        if (wasNegativeMinimumMode && atMinimumPv) reason = 'Leaving negative price minimum mode';
        else if (!marketValid) reason = 'Market price unavailable';
        else if (pvPower < nightRestorePower) reason = 'Night / low PV production';
        else if (market > limitingPrice) reason = 'Market price recovered';
        else if (targetIsFull) reason = 'Calculated target is full power';
        else reason = 'Restore condition';
    } else if (shouldAdjust) {
        pvAction = 'adjust';
        status = 'PV dynamically adjusted';
        if (grid < exportStart) reason = 'Export above threshold';
        else if (grid > importRecalc) reason = 'Import above recalculation threshold';
        else reason = 'Dynamic adjustment';
    } else {
        status = wantsMinimumPv ? 'PV minimum active' : (market <= limitingPrice ? 'Monitoring low price' : 'PV full / price OK');
        reason = cooldownJustFinished
            ? 'Cooldown finished; waiting until next evaluation'
            : (targetIsMinimum && atMinimumPv
                ? 'PV already at minimum; waiting until higher target is needed'
                : (canChangePv ? 'No target change needed' : 'PV cooldown active'));
    }

    // Track whether the current minimum state came from negative-price mode.
    // This prevents the export-limiting minimum path from restoring and limiting in a loop.
    if (wantsMinimumPv) {
        flow.set('homePvControlNegativeMinimumActive', true);
    } else if (wasNegativeMinimumMode && (pvAction === 'restore' || !atMinimumPv)) {
        flow.set('homePvControlNegativeMinimumActive', false);
    }

    // Build inverter service messages as a list for split node.
    let calls = [];
    if (pvAction === 'minimum') {
        let changedMinimum = [];
        for (const inv of inverters) {
            if (inv.current > (inv.minimum_power + deadband)) {
                calls.push(serviceMsg('number', 'set_value', { value: inv.minimum_power }, { entity_id: inv.limit_entity }));
                changedMinimum.push(`${inv.name} ${inv.current}→${inv.minimum_power}W`);
            }
        }
        if (changedMinimum.length > 0) insight('Home PV Control', 'Negative price', `all-in=${allIn} €/kWh; ${changedMinimum.join(', ')}`);
        if (notify) {
            notification = {
                title: 'PV minimum - negative price',
                message:
`PV forced to minimum.

Reason: ${reason}

All-in price: ${allIn} €/kWh
Market price: ${market} €/kWh
PV power: ${pvPower} W
Grid power: ${grid} W

Inverters changed: ${calls.length}`
            };
        }
    } else if (pvAction === 'restore') {
        let changedRestore = [];
        for (const inv of inverters) {
            if (inv.current < (inv.full_power - deadband)) {
                calls.push(serviceMsg('number', 'set_value', { value: inv.full_power }, { entity_id: inv.limit_entity }));
                changedRestore.push(`${inv.name} ${inv.current}→${inv.full_power}W`);
            }
        }
        if (changedRestore.length > 0) insight('Home PV Control', 'Restore', `${reason}; ${changedRestore.join(', ')}`);
        if (notify) {
            notification = {
                title: 'PV restored',
                message:
`PV restored to full power.

Reason: ${reason}

Market price: ${market} €/kWh
PV power: ${pvPower} W
Grid power: ${grid} W

Inverters changed: ${calls.length}`
            };
        }
    } else if (pvAction === 'adjust') {
        let changedAdjust = [];
        for (const t of targets) {
            if (t.changed) {
                calls.push(serviceMsg('number', 'set_value', { value: t.target }, { entity_id: t.entity }));
                changedAdjust.push(`${t.name} ${t.current}→${t.target}W`);
            }
        }
        if (changedAdjust.length > 0) insight('Home PV Control', 'PV limit', `${reason}; target ${targetTotal}W; ${changedAdjust.join(', ')}`);
        if (notify) {
            notification = {
                title: 'PV dynamically adjusted',
                message:
`PV dynamically adjusted.

Reason: ${reason}

Market price: ${market} €/kWh
PV power: ${pvPower} W
Grid power: ${grid} W

Target total PV limit: ${targetTotal} W
Inverters changed: ${calls.length}`
            };
        }
    }

    if (calls.length > 0) {
        outputs[0] = calls;
        if (['adjust', 'minimum', 'restore'].includes(pvAction)) {
            flow.set('homePvControlLastPvWriteMs', now);
            flow.set('homePvControlCooldownUntilMs', now + cooldownMs);
            cooldownActiveNow = cooldownMs > 0;
        }
    }

    // Battery strategy switching via HBC strategy selector.
    if (controlHbc) {
        const chargeEnter = chargePrice;
        const chargeExit = chargePrice + hysteresis;
        const expensiveEnter = expensivePrice;
        const expensiveExit = expensivePrice - hysteresis;

        const wantsCharge =
            allInValid &&
            (
                allIn < chargeEnter ||
                (currentStrategy === 'Charge' && allIn < chargeExit)
            );

        const wantsExpensive =
            allInValid &&
            (
                allIn >= expensiveEnter ||
                (currentStrategy === expensiveStrategy && allIn >= expensiveExit)
            );

        const wantsBalanced = allInValid && !wantsCharge && !wantsExpensive;

        if (wantsCharge && currentStrategy !== 'Charge') {
            batteryOption = 'Charge';
        } else if (wantsExpensive && currentStrategy !== expensiveStrategy) {
            batteryOption = expensiveStrategy;
        } else if (wantsBalanced && currentStrategy !== balancedStrategy) {
            batteryOption = balancedStrategy;
        }

        if (batteryOption) {
            insight('Battery Strategy', 'Selected', `${currentStrategy} → ${batteryOption}`);
            outputs[6] = serviceMsg('input_select', 'select_option', { option: batteryOption }, { entity_id: hbcStrategyEntity });
            if (notify) {
                let batteryReason = '';
                if (batteryOption === 'Charge') {
                    batteryReason = `all-in price ${allIn} €/kWh is below charge threshold ${chargeEnter} €/kWh.`;
                } else if (batteryOption === expensiveStrategy) {
                    batteryReason = `all-in price ${allIn} €/kWh is at or above expensive threshold ${expensiveEnter} €/kWh.`;
                } else {
                    batteryReason = `all-in price ${allIn} €/kWh is in the balanced price zone.`;
                }
                notificationCalls.push(serviceMsg('persistent_notification', 'create', {
                    notification_id: 'battery_ems_status',
                    title: 'Battery strategy changed',
                    message: `Battery strategy changed to ${batteryOption}.\n\nReason: ${batteryReason}\n\nPrevious strategy: ${currentStrategy}`
                }, {}));
            }
        }
    }
}

// Cooldown insight: log exactly once when cooldown starts and exactly once when it finishes.
// The cooldown-finished evaluation is intentionally blocked from PV changes by canChangePv above.
if (cooldownActiveNow && !previousCooldownActive) {
    insight('Home PV Control', 'Cooldown', `PV cooldown active (${cooldownSeconds} sec)`);
} else if (cooldownJustFinished) {
    insight('Home PV Control', 'Cooldown', 'PV cooldown finished; PV changes allowed on next evaluation');
}
flow.set('homePvControlCooldownActive', cooldownActiveNow);
if (cooldownJustFinished) {
    flow.set('homePvControlCooldownUntilMs', 0);
}

// Helper/status updates
// outputs[8] may already carry the HBC toggle-off message from above.
outputs[1] = serviceMsg('input_text', 'set_value', { value: String(status).slice(0,255) }, { entity_id: 'input_text.pv_ems_status' });
outputs[2] = serviceMsg('input_text', 'set_value', { value: String(reason).slice(0,255) }, { entity_id: 'input_text.pv_ems_reason' });
outputs[3] = serviceMsg('input_text', 'set_value', { value: (new Date().toLocaleString() + ' - ' + status).slice(0,255) }, { entity_id: 'input_text.pv_ems_last_action' });
outputs[4] = serviceMsg('input_text', 'set_value', { value: JSON.stringify({
    cooldown_active: cooldownActiveNow,
    pv_limited: inverters.some(inv => inv.current < (inv.full_power - deadband)),
    negative_price_mode: wantsMinimumPv,
    at_minimum_pv: atMinimumPv,
    hbc_detected: hasHbc,
    hbc_enabled: controlHbc,
    target_total: targetTotal
}).slice(0,255) }, { entity_id: 'input_text.pv_ems_last_targets_json' });

if (strEntity('input_text.pv_ems_hbc_status', '') !== hbcStatusText) {
    const hbcStatusMsg = serviceMsg('input_text', 'set_value', { value: hbcStatusText.slice(0,255) }, { entity_id: 'input_text.pv_ems_hbc_status' });
    outputs[8] = outputs[8] ? [outputs[8], hbcStatusMsg] : hbcStatusMsg;
}
// Rolling insight log: keep last 10 unique decisions in HBC-like rows.
// Duplicate detection ignores the timestamp, so repeated monitor/cooldown messages do not fill the list.
let insightCalls = [];
const oldInsights = [];
for (let i = 1; i <= 10; i++) {
    oldInsights.push(strEntity(`input_text.pv_ems_insight_${i}`, ''));
}

const merged = [];
const seenBodies = new Set();
for (const item of [...newInsights].reverse()) {
    if (!seenBodies.has(item.key)) {
        merged.push(item.line);
        seenBodies.add(item.key);
    }
}
for (const line of oldInsights) {
    const body = insightBody(line);
    if (line && body && !seenBodies.has(body)) {
        merged.push(line);
        seenBodies.add(body);
    }
}
const nextInsights = merged.slice(0, 10);
let changedInsights = false;
for (let i = 1; i <= 10; i++) {
    const value = String(nextInsights[i - 1] || '').slice(0,255);
    if (value !== String(oldInsights[i - 1] || '')) changedInsights = true;
    insightCalls.push(serviceMsg('input_text', 'set_value', {
        value
    }, { entity_id: `input_text.pv_ems_insight_${i}` }));
}
outputs[7] = changedInsights ? insightCalls : null;

if (notification) {
    notificationCalls.push(serviceMsg('persistent_notification', 'create', {
        notification_id: 'home_pv_control_status',
        title: notification.title,
        message: notification.message
    }, {}));
}
outputs[5] = notificationCalls.length > 0 ? notificationCalls : null;


return outputs;

// Build dropdown options for main dashboard entity selectors.
// Safe v2: fast startup, keeps previous/current selections, and does NOT cut the list alphabetically.
function states() {
    return global.get('homeassistant.homeAssistant.states') || {};
}
function isRealEntity(e) {
    return typeof e === 'string' && e.includes('.') && !['unknown', 'unavailable', 'select_entity_first', ''].includes(e);
}
function currentOptions(entity_id) {
    const ent = states()[entity_id];
    const opts = ent && ent.attributes && Array.isArray(ent.attributes.options) ? ent.attributes.options : [];
    return opts.filter(isRealEntity);
}
function uniqueKeepOrder(arr) {
    const seen = new Set();
    const out = [];
    for (const e of arr) {
        if (isRealEntity(e) && !seen.has(e)) {
            seen.add(e);
            out.push(e);
        }
    }
    return out;
}
function alpha(arr) {
    return Array.from(arr).sort((a,b) => a.localeCompare(b));
}
function svc(entity_id, preferred, fallback) {
    const s = states();
    const current = s[entity_id] && s[entity_id].state;

    // Order matters:
    // 1 selected value
    // 2 old dropdown options
    // 3 best matching entities
    // 4 all fallback entities
    // No 250 cut: cutting caused lists to stop around sensor.i* alphabetically.
    let list = uniqueKeepOrder([
        current,
        ...currentOptions(entity_id),
        ...alpha(preferred || []),
        ...alpha(fallback || [])
    ]);

    list = ['select_entity_first', ...list.filter(e => e !== 'select_entity_first')];

    return {
        payload: {
            action: 'input_select.set_options',
            target: { entity_id },
            data: { options: list }
        }
    };
}

const s = states();
const all = Object.keys(s);
const sensors = all.filter(e => e.startsWith('sensor.'));
const numbers = all.filter(e => e.startsWith('number.'));
const inputNumbers = all.filter(e => e.startsWith('input_number.') && !e.startsWith('input_number.pv_ems_'));
const inputSelects = all.filter(e => e.startsWith('input_select.') && !e.startsWith('input_select.pv_ems_'));
const selects = all.filter(e => e.startsWith('select.'));
const switches = all.filter(e => e.startsWith('switch.'));
const binarySensors = all.filter(e => e.startsWith('binary_sensor.'));

// Only block when HA states are really almost empty during reload/startup.
// This keeps the dropdown fast but prevents overwriting with only select_entity_first.
if (all.length < 30 || sensors.length < 3) {
    node.warn(`Home Assistant states not ready yet (${all.length} entities, ${sensors.length} sensors). Dropdowns kept unchanged. Will retry in 60s.`);
    return null;
}

const powerSensors = sensors.filter(e => /power|meter|grid|p1|pv|solar|opendtu|ac_power|watt/i.test(e));
const priceSensors = sensors.filter(e => /price|tibber|energy|electricity|market|tariff|cost|eur|kwh/i.test(e));
const pvPowerSensors = sensors.filter(e => /pv|solar|opendtu|inverter|ac_power|power|hms/i.test(e));
const inverterNumbers = numbers.filter(e => /limit|power|inverter|hms|opendtu|pv|solar|watt/i.test(e));
const strategyEntities = [
    'input_select.house_battery_strategy',
    ...inputSelects,
    ...selects
];

let msgs = [];
msgs.push(svc('input_select.pv_ems_grid_power_sensor_picker', powerSensors, sensors));
msgs.push(svc('input_select.pv_ems_market_price_sensor_picker', priceSensors, sensors));
msgs.push(svc('input_select.pv_ems_all_in_price_sensor_picker', priceSensors, sensors));
msgs.push(svc('input_select.pv_ems_pv_power_sensor_picker', pvPowerSensors, sensors));
msgs.push(svc('input_select.pv_ems_battery_strategy_entity_picker', strategyEntities, [...inputSelects, ...selects]));

for (let i = 1; i <= 10; i++) {
    msgs.push(svc(`input_select.pv_ems_pv${i}_limit_number_picker`, inverterNumbers, [...numbers, ...inputNumbers]));
}

return [msgs];
